import { createBrowserRouter } from "react-router";

import { routerAfterEach, routerBeforeEach, routerInitReady } from "./router-global-hooks";
import { routes } from "./routes";

export const router = createBrowserRouter(
	routes,
	{
		basename: import.meta.env.BASE_URL,
	},
);

export async function setupRouter() {
	// router beforeEach
	router.getBlocker("beforeEach", routerBeforeEach(router));
	// router afterEach
	router.subscribe(routerAfterEach);

	await routerInitReady(router);
}

export default router;

import type { BlockerFunction } from "react-router";
import type { ReactRouterType, RouterSubscriber } from "./types";

import { useAuthStore, usePermissionStore, usePreferencesStore, useUserStore } from "#src/store";
import { NProgress } from "#src/utils";

import { matchRoutes } from "react-router";

import { LOGIN, ROUTE_WHITE_LIST } from "./constants";
import { isDynamicRoutingEnabled } from "./routes/config";
import { replaceBaseWithRoot } from "./utils";

// 不需要登录路由的路由白名单
const noLoginWhiteList = Array.from(ROUTE_WHITE_LIST).filter(item => item !== LOGIN);

/**
 * 全局前置守卫，用于在路由跳转前执行一些操作
 *
 * 触发条件：使用 react-router 中的 navigate、Link 等方法跳转路由时触发
 *
 * @returns 返回 true 则取消当前导航，返回 false 则继续导航
 */
export const routerBeforeEach: (reactRouter: ReactRouterType) => BlockerFunction = reactRouter => ({ nextLocation }) => {
	const { transitionProgress } = usePreferencesStore.getState();
	/* 开启进度条动画 */
	transitionProgress && NProgress.start();

	const matches = matchRoutes(
		reactRouter.routes,
		nextLocation,
		import.meta.env.BASE_URL,
	) ?? [];
	const currentRoute = matches[matches.length - 1];

	const { pathname, search } = nextLocation;
	const pathnameWithoutBase = replaceBaseWithRoot(pathname);

	/* 路由白名单 */
	if (noLoginWhiteList.includes(pathnameWithoutBase)) {
		return false;
	}
	/* 是否登录 */
	const isLogin = Boolean(useAuthStore.getState().token);
	// 未登录
	if (!isLogin) {
		// 未登录且目标页不是登录页，则跳转到登录页
		if (pathnameWithoutBase !== LOGIN) {
			// pathnameWithoutBase 长度大于 1，则携带当前路径跳转登录页
			if (pathnameWithoutBase.length > 1) {
				reactRouter.navigate(`/login?redirect=${pathnameWithoutBase}${search}`);
				return true;
			}
			else {
				reactRouter.navigate("/login");
				return true;
			}
		}
		// 未登录且目标页是登录页，放行
		else {
			return false;
		}
	}

	/* --------------- 以下为已登录的处理逻辑 ------------------ */

	/* --------------- Start ------------------ */
	/* 如果是根路由则跳转到首页 */
	if (pathname === import.meta.env.BASE_URL) {
		reactRouter.navigate(import.meta.env.VITE_BASE_HOME_PATH, { replace: true });
		return true;
	}
	/* 已登录时匹配 login 路由，跳转到首页 */
	if (pathnameWithoutBase === "/login") {
		reactRouter.navigate(import.meta.env.VITE_BASE_HOME_PATH, { replace: true });
		return true;
	}
	/* --------------- End ------------------ */

	/**
	 * 路由权限校验逻辑
	 */
	const userRoles = useUserStore.getState().roles;
	const routeRoles = currentRoute?.route?.handle?.roles;
	const ignoreAccess = currentRoute?.route?.handle?.ignoreAccess;
	const hasChildren = currentRoute?.route?.children?.filter(item => !item.index)?.length;
	// 忽略权限校验
	if (ignoreAccess === true) {
		return false;
	}
	// 如果当前路由有子路由，则跳转到 404 页面
	if (hasChildren && hasChildren > 0) {
		reactRouter.navigate("/error/404");
		return true;
	}

	// 路由权限校验
	const hasRoutePermission = userRoles.some(role => routeRoles?.includes(role));
	// 未通过权限校验，则跳转到 403 页面，如果路由上没有设置 roles，则默认放行
	if (routeRoles && routeRoles.length && !hasRoutePermission) {
		reactRouter.navigate("/error/403");
		return true;
	}

	return false;
};

/**
 * 路由守卫，在路由跳转完成后执行
 */
export const routerAfterEach: RouterSubscriber = (routerState) => {
	const { transitionProgress } = usePreferencesStore.getState();
	if (routerState.navigation.state === "idle") {
		/* 路由变化更新文档标题的逻辑放到了路由守卫组件中（guard.tsx） */
		/* 关闭进度条动画 */
		transitionProgress && NProgress.done();
	}
};

/**
 * 路由初始化完成后执行（只会执行一次）
 *
 * 为什么需要 routerInitReady ？
 * [应用初次加载/刷新浏览器/浏览器输入地址回车]并不会触发 routerBeforeEach 钩子，所以需要 routerInitReady 模仿一次 routerBeforeEach。
 */
export async function routerInitReady(reactRouter: ReactRouterType) {
	/* 顶部进度条 */
	const { transitionProgress } = usePreferencesStore.getState();
	// 是否开启进度条动画
	if (transitionProgress) {
		NProgress.start();
		function handleDomReady() {
			NProgress.done();
			document.removeEventListener("DOMContentLoaded", handleDomReady);
		}
		document.addEventListener("DOMContentLoaded", handleDomReady);
	}

	const currentRoute = reactRouter.state.matches[reactRouter.state.matches.length - 1];
	const { pathname, search } = reactRouter.state.location;
	const pathnameWithoutBase = replaceBaseWithRoot(pathname);

	/* 路由白名单 */
	if (noLoginWhiteList.includes(pathnameWithoutBase)) {
		return;
	}
	/* 是否登录 */
	const isLogin = Boolean(useAuthStore.getState().token);
	// 未登录
	if (!isLogin) {
		// 未登录且目标页不是登录页，则跳转到登录页
		if (pathnameWithoutBase !== LOGIN) {
			// pathnameWithoutBase 长度大于 1，则携带当前路径跳转登录页
			if (pathnameWithoutBase.length > 1) {
				reactRouter.navigate(`/login?redirect=${pathnameWithoutBase}${search}`);
				return;
			}
			else {
				reactRouter.navigate("/login");
				return;
			}
		}
		// 未登录且目标页是登录页，放行
		else {
			return;
		}
	}

	/* --------------- 以下为已登录的处理逻辑 ------------------ */

	// 已登录，获取动态路由
	const { handleAsyncRoutes } = usePermissionStore.getState();

	// 初始化一个空数组来存放 Promise 对象
	const promises = [];

	// 总是添加获取用户信息的 Promise
	promises.push(useUserStore.getState().getUserInfo());

	// 如果启用了动态路由，则添加处理动态路由的 Promise
	if (isDynamicRoutingEnabled) {
		promises.push(handleAsyncRoutes());
	}

	/**
	 * 用户信息包含了用户角色，需要在获取菜单权限前面获取，用于权限校验
	 */
	const results = await Promise.allSettled(promises);
	const hasError = results.some(result => result.status === "rejected");

	// 网络请求失败，跳转到 500 页面
	if (hasError) {
		const unAuthorized = results.some((result: any) => result.reason.response.status === 401);
		if (!unAuthorized) {
			reactRouter.navigate("/error/500");
		}
		return;
	}

	/* --------------- Start ------------------ */
	// 判断路由跳转逻辑，需要在获取动态路由之后，防止路由跳转直接进入 getBlocker 中然后发送请求，但是 getBlocker 不支持异步
	/* 如果是根路由则跳转到首页 */
	if (pathname === import.meta.env.BASE_URL) {
		reactRouter.navigate(import.meta.env.VITE_BASE_HOME_PATH, { replace: true });
		return;
	}

	/* 已登录时匹配 login 路由，跳转到首页 */
	if (pathnameWithoutBase === "/login") {
		reactRouter.navigate(import.meta.env.VITE_BASE_HOME_PATH, { replace: true });
		return;
	}

	/**
	 * 需要替换当前路由
	 * https://router.vuejs.org/guide/advanced/dynamic-routing#Adding-routes
	 *
	 * 为什么需要替换当前路由？
	 * 1. 初始化路由
	 * 2. 导航进入动态路由地址，例如 /system/user
	 * 3. 动态路由未添加到路由，所以地址栏中依然是 /system/user 但匹配到的路由是 error/404 路由
	 * 4. 添加完动态路由后，使用 replace 触发地址栏的路径匹配对应的路由
	 *
	 * 注意：navigate 方法调用之后会触发 routerBeforeEach 钩子
	 */

	if (
		isDynamicRoutingEnabled
		/**
		 * 初次导航到动态路由，页面会匹配 404 路由
		 * 表现为：页面路径 currentRoute.pathname 和匹配的路由（currentRoute.route.id）不同，则替换当前路由
		 * 如果是初次导航到静态路由，则不需要触发替换
		 */
		&& currentRoute.pathname !== currentRoute.route.id) {
		/**
		 * 替换当前路由后，会触发 routerBeforeEach 钩子
		 */
		return reactRouter.navigate(`${pathnameWithoutBase}${search}`, { replace: true });
	}

	/**
	 * 纯静态路由，则会支持下面的代码
	 * 路由权限校验逻辑
	 */
	const userRoles = useUserStore.getState().roles;
	const routeRoles = currentRoute?.route?.handle?.roles;
	const ignoreAccess = currentRoute?.route?.handle?.ignoreAccess;
	const hasChildren = currentRoute?.route?.children?.filter(item => !item.index)?.length;
	// 忽略权限校验
	if (ignoreAccess === true) {
		return;
	}
	// 如果当前路由有子路由，则跳转到 404 页面
	if (hasChildren && hasChildren > 0) {
		return reactRouter.navigate("/error/404");
	}

	// 路由权限校验
	const hasRoutePermission = userRoles.some(role => routeRoles?.includes(role));
	// 未通过权限校验，则跳转到 403 页面，如果路由上没有设置 roles，则默认放行
	if (routeRoles && routeRoles.length && !hasRoutePermission) {
		return reactRouter.navigate("/error/403");
	}
}

import type { ReactNode } from "react";
import type { IndexRouteObject, NonIndexRouteObject, createBrowserRouter as RemixRouter } from "react-router";

export interface IndexRouteMeta extends Omit<IndexRouteObject, "id"> {
	redirect?: string
	handle: RouteMeta
}
export interface NonIndexRouteMeta extends Omit<NonIndexRouteObject, "id"> {
	redirect?: string
	handle: RouteMeta
	children?: AppRouteRecordRaw[]
}

export type AppRouteRecordRaw = IndexRouteMeta | NonIndexRouteMeta;

export interface RouteMeta {
	/**
	 * 路由标题，通常用于页面标题或者侧边栏菜单显示
	 */
	title: ReactNode

	/**
	 * 菜单图标，用于侧边栏菜单项的图标显示
	 */
	icon?: ReactNode

	/**
	 * 菜单排序，用于控制侧边栏菜单的显示顺序
	 */
	order?: number

	/**
	 * 用于配置页面的权限，只有拥有对应权限的用户才能访问页面，不配置则不需要权限。
	 */
	roles?: string[]

	/**
	 * 页面内按钮级别的权限，用于控制页面内按钮的显示和隐藏
	 */
	permissions?: string[]

	/**
	 * 设置页面是否开启缓存，开启后页面会缓存，不会重新加载，仅在标签页启用时有效。
	 * @default true
	 */
	keepAlive?: boolean

	/**
	 * 是否在菜单中隐藏，用于控制某些路由不在侧边栏菜单中显示
	 */
	hideInMenu?: boolean

	/**
	 * iframe链接，如果路由需要在iframe中加载外部页面时使用
	 */
	iframeLink?: string

	/**
	 * 外部链接，点击后直接在新标签页中打开
	 */
	externalLink?: string

	/**
	 * 是否忽略权限，即无需登录即可访问
	 */
	ignoreAccess?: boolean

	/**
	 * @description 指定当前激活的菜单，适用于动态路由情景下激活父菜单
	 * @example 从父路由 '/user/info' 导航到子路由 '/user/info/1' 时，可以手动手动指定以高亮显示父菜单 '/user/info'
	 */
	currentActiveMenu?: string

	/**
	 * 当前路由为请求后端接口得到的
	 */
	backstage?: boolean
}

export type ReactRouterType = ReturnType<typeof RemixRouter>;
export type RouterSubscriber = Parameters<ReactRouterType["subscribe"]>[0];
export type RouterState = ReactRouterType["state"];
export type RouterNavigate = ReactRouterType["navigate"];

// 使用类型别名提取公共类型
export type RouteFileModule = Record<string, { default: AppRouteRecordRaw[] }>;

import type { MenuItemType } from "#src/layout/layout-menu/types";
import type { AppRouteRecordRaw, RouteFileModule } from "./types";

import { Iframe } from "#src/components/iframe";
import { ContainerLayout } from "#src/layout";
import { isString } from "#src/utils";

import * as antdIcons from "@ant-design/icons";
import { createElement } from "react";
import { Link } from "react-router";

const allAntdIcons: { [key: string]: any } = antdIcons;

/**
 * 合并路由模块
 *
 * @param routes 路由模块数组
 * @returns 合并后的路由记录数组
 */
export function mergeRouteModules(...routes: RouteFileModule[]) {
	return routes.flatMap((modules) => {
		return Object.keys(modules).reduce<AppRouteRecordRaw[]>(
			(list, key) => {
				const mod = modules[key].default ?? {};
				const modList = Array.isArray(mod) ? [...mod] : [mod];
				return [...list, ...addIdToRoutes(modList)];
			},
			[],
		);
	});
}

/**
 * 为路由数组中的每个路由对象添加一个唯一的 ID，该 ID 默认为路由的路径。
 * 如果路由对象包含子路由，则递归地为每个子路由添加 ID。
 *
 * @param routes 原始路由数组
 * @returns 带有 ID 的路由数组
 */
/**
 * Adds a unique ID to each route object in the routes array, defaulting the ID to the route's path.
 * If a route object contains child routes, recursively adds IDs to each child route.
 *
 * @param routes The original array of routes
 * @returns The array of routes with IDs
 */
export function addIdToRoutes(routes: AppRouteRecordRaw[], parentId = "") {
	return routes.map((route) => {
		const newRoute = { ...route, id: route.index ? `${parentId}/` : route.path };

		if (newRoute.children && newRoute.children.length > 0) {
			newRoute.children = addIdToRoutes(newRoute.children, route.path);
		}

		return newRoute;
	});
}

/**
 * 根据路由列表生成菜单项数组
 *
 * @param routeList 路由列表，类型为 AppRouteRecordRaw 数组
 * @returns 返回菜单项数组，数组元素类型为 MenuItemType
 */
export function getMenuItems(routeList: AppRouteRecordRaw[]) {
	return routeList.reduce<MenuItemType[]>((acc, item) => {
		const label = item.handle?.title;
		const externalLink = item?.handle?.externalLink;
		const iconName = item?.handle?.icon;

		const menuItem: MenuItemType = {
			key: item.path!,
			icon: isString(iconName) ? createElement(allAntdIcons[iconName]) : iconName,
			label: externalLink
				? createElement(
					Link,
					{ to: externalLink, target: "_blank", rel: "noopener noreferrer" },
					label,
				)
				: (
					label
				),
		};
		if (Array.isArray(item.children) && item.children.length > 0) {
			// 过滤掉非首页，且不显示在菜单中的路由
			const noIndexRoute = item.children.filter(route => !route.index && !route?.handle?.hideInMenu);
			if (noIndexRoute.length > 0) {
				menuItem.children = getMenuItems(noIndexRoute);
			}
		}
		if (item?.handle?.hideInMenu) {
			return acc;
		}
		return [...acc, menuItem];
	}, []);
}

/** 按照路由中 order 升序来排序路由 */
export function ascending(arr: AppRouteRecordRaw[]) {
	return arr.map((routeItem, routeIndex) => ({
		...routeItem,
		handle: {
			...routeItem.handle,
			// 当 order 不存在时，根据顺序自动创建
			order: routeItem?.handle?.order || routeIndex + 2,
		},
	})).sort(
		(a, b) => {
			return a?.handle?.order - b?.handle?.order;
		},
	);
}

/**
 * 将路由数组扁平化为一个以路径为键，层级和索引为值的对象
 *
 * @param routes 路由数组
 * @returns 扁平化后的路由对象，以路径为键，层级和索引为值
 */

export function flattenRoutes(routes: AppRouteRecordRaw[]) {
	const result: Record<string, AppRouteRecordRaw> = {};

	function traverse(items: AppRouteRecordRaw[], parent?: AppRouteRecordRaw) {
		items.forEach((item) => {
			if (item.index && parent?.path) {
				result[`${parent.path}/`] = item;
			}
			if (item.path) {
				result[item.path] = item;
			}
			if (item.children && item.children.length > 0) {
				traverse(item.children, item);
			}
		});
	}

	traverse(routes);
	return result;
}

// https://cn.vitejs.dev/guide/features.html#glob-import
const modulesRoutes = import.meta.glob<
	Record<string, React.ComponentType>
>([
	"/src/pages/**/*.tsx",
	// Fix plugin vite:reporter
	"!/src/pages/error/page-error/*.tsx",
]);

/** 过滤后端传来的动态路由 重新生成规范路由 */
export function addAsyncRoutes(arrRoutes: Array<AppRouteRecordRaw>) {
	if (!arrRoutes || !arrRoutes.length)
		return [];
	const modulesRoutesKeys = Object.keys(modulesRoutes);
	arrRoutes.forEach((v: AppRouteRecordRaw) => {
		// 将 backstage 属性加入 handle，标识此路由为后端返回路由
		v.handle.backstage = true;

		if (v.handle?.iframeLink) {
			v.Component = Iframe;
		}
		else if (v.children && v.children?.length) {
			v.Component = ContainerLayout;
		}
		else {
			const routePath = v.path!;
			const index = modulesRoutesKeys.findIndex(ev => ev === `/src/pages${routePath}/index.tsx`);
			// https://github.com/remix-run/react-router/tree/dev/examples/lazy-loading-router-provider
			// https://reactrouter.com/en/main/route/lazy
			v.lazy = async () => {
				const DefaultComponent = await modulesRoutes[modulesRoutesKeys[index]]();
				return {
					Component: DefaultComponent.default,
				};
			};
		}
		if (v?.children && v.children.length) {
			addAsyncRoutes(v.children);
		}
	});
	return addIdToRoutes(arrRoutes);
}

/**
 * 将基础路径替换为根路径
 * 假如开启了 Vite 的 base 配置，React Router Location.pathname 获取到的路径前面有 base
 * 开发的时候是不根据 base 开发的，所以当使用判断逻辑，或者导航到 pathname 需要将 base 去掉
 *
 * 开始 base:
 * 生产：/base/about
 * 开发：/about
 *
 * @param pathname 当前路径
 * @returns 替换后的路径
 */
export function replaceBaseWithRoot(pathname: string) {
	const base = import.meta.env.BASE_URL;

	if (pathname.length > 1) {
		return pathname.slice(base.length - 1);
	}

	return pathname;
}

/**
 * 移除路径末尾的斜杠
 * @param {string} pathname - 需要处理的路径
 * @returns {string} 移除末尾斜杠后的路径
 * @example
 * removeTrailingSlash('/about/') // 返回 '/about'
 * removeTrailingSlash('/about')  // 返回 '/about'
 */
export function removeTrailingSlash(pathname: string) {
	return pathname.endsWith("/") ? pathname.slice(0, -1) : pathname;
}

