import LayoutSidebar from "../layout-sidebar";
import LayoutTabbar from "../layout-tabbar";
import { BreadcrumbViews, Logo } from "../widgets";
import { LayoutContext } from "./layout-context";

const { useBreakpoint } = Grid;
const useStyles = createUseStyles({
	drawerStyles: {
		"& .ant-drawer-body": {
			"padding": 0,
			"&>ul": {
				paddingTop: "1em",
			},
		},
		"& .ant-drawer-header": {
			display: "none",
		},
	},
});

/**
 * Please do not use this component through lazy, otherwise the switching routing page will flash.
 * 请不要通过 lazy 使用这个组件，否则切换路由页面会发生闪动。
 *
 * NO:
 * const ContainerLayout = lazy(() => import("#src/layout/container-layout"));
 *
 * YES:
 * import { ContainerLayout } from "#src/layout";
 */
export default function ContainerLayout() {
	const [sidebarCollapsed, setSidebarCollapsed] = useState(false);
	const classes = useStyles();
	const screens = useBreakpoint();
	const { isTopNav, isTwoColumnNav, isMixedNav, sidebarWidth, sideCollapseWidth } = useLayout();
	const isMaximize = useTabsStore(state => state.isMaximize);
	const tabbarEnable = usePreferencesStore(state => state.tabbarEnable);
	const { isMobile } = useDeviceType();
	const { sideNavItems, topNavItems, handleMenuSelect } = useMenu();

	useEffect(() => {
		/* iPad */
		if (screens.lg && !screens.xl) {
			setSidebarCollapsed(true);
		}
		/* PC */
		else if (screens.xl) {
			setSidebarCollapsed(false);
		}
		/* Mobile */
		else if (screens.xs || (screens.sm && !screens.md)) {
			setSidebarCollapsed(false);
		}
	}, [screens]);

	const layoutContextValue = useMemo(() => ({ sidebarCollapsed, setSidebarCollapsed }), [sidebarCollapsed, setSidebarCollapsed]);

	const sidebarEnableState = useMemo(() => !isTopNav, [isTopNav]);
	const computedSidebarWidth = useMemo(() => {
		if (isMaximize || isMobile) {
			return 0;
		}
		const currentSidebarWidth = sidebarCollapsed ? sideCollapseWidth : sidebarWidth;
		if (isTwoColumnNav) {
			/* 双列导航，第一列默认宽度 */
			return currentSidebarWidth + 80;
		}
		if (sidebarEnableState) {
			return currentSidebarWidth;
		}
		return 0;
	}, [
		// Mobile
		isMobile,
		isMaximize,
		isTwoColumnNav,
		sidebarEnableState,
		sidebarWidth,
		sidebarCollapsed,
		sideCollapseWidth,
	]);

	return (
		<LayoutContext.Provider value={layoutContextValue}>
			<section
				style={{
					paddingLeft: computedSidebarWidth,
				}}
				className={cn(
					"transition-all flex flex-col h-screen",
				)}
			>
				<LayoutHeader>
					{isTopNav || isMixedNav
						? (
							<>
								{isTopNav ? <Logo sidebarCollapsed={false} className="mr-8" /> : null}
								<LayoutMenu mode="horizontal" menus={topNavItems} handleMenuSelect={handleMenuSelect} />
							</>
						)
						: <BreadcrumbViews />}
				</LayoutHeader>
				{tabbarEnable ? <LayoutTabbar /> : null}

				{/* Mobile */}
				{
					isMobile
						? (
							<Drawer
								open={sidebarCollapsed}
								placement="left"
								width="clamp(200px, 50vw, 210px)"
								className={cn(classes.drawerStyles)}
								onClose={() => setSidebarCollapsed(false)}
							>
								<LayoutMenu autoOpenMenu menus={sideNavItems} handleMenuSelect={handleMenuSelect} />
							</Drawer>
						)
						: null
				}

				{/* PC */}
				{
					sidebarEnableState && !isTwoColumnNav
						? (
							<LayoutSidebar
								computedSidebarWidth={computedSidebarWidth}
							>
								<LayoutMenu
									autoOpenMenu
									menus={sideNavItems}
									handleMenuSelect={handleMenuSelect}
								/>
							</LayoutSidebar>
						)
						: null
				}
				{
					isTwoColumnNav
						? (
							<LayoutMixedSidebar
								computedSidebarWidth={computedSidebarWidth}
								sideNavItems={sideNavItems}
								topNavItems={topNavItems}
								handleMenuSelect={handleMenuSelect}
							/>
						)
						: null
				}

				<LayoutContent />

				<LayoutFooter className="bg-colorBgContainer" />
			</section>
		</LayoutContext.Provider>
	);
}

import { useDeviceType } from "#src/hooks";
import {
	MIXED_NAVIGATION,
	SIDE_NAVIGATION,
	TOP_NAVIGATION,
	TWO_COLUMN_NAVIGATION,
} from "#src/layout/widgets/preferences/blocks/layout/constants";
import { usePreferencesStore } from "#src/store";

import { useMemo } from "react";

/**
 * 获取当前页面的布局类型信息
 *
 * @returns 返回包含当前布局类型信息的对象，包含：
 * - currentLayout: 当前导航类型
 * - isSideNav: 是否为侧边导航
 * - isTopNav: 是否为顶部导航
 * - isMixedNav: 是否为混合导航
 * - isTwoColumnNav: 是否为双列导航
 */
export function useLayout() {
	const { isMobile } = useDeviceType();
	// LayoutType
	const navigationStyle = usePreferencesStore(state => state.navigationStyle);
	const sidebarWidth = usePreferencesStore(state => state.sidebarWidth);
	const sideCollapseWidth = usePreferencesStore(state => state.sideCollapseWidth);

	/**
	 * 当前导航类型
	 */
	const currentLayout = useMemo(
		() => isMobile ? SIDE_NAVIGATION : navigationStyle,
		[isMobile, navigationStyle],
	);

	/**
	 * 是否为侧边导航
	 */
	const isSideNav = useMemo(
		() => currentLayout === SIDE_NAVIGATION,
		[currentLayout],
	);

	/**
	 * 是否为顶部导航
	 */
	const isTopNav = useMemo(
		() => currentLayout === TOP_NAVIGATION,
		[currentLayout],
	);

	/**
	 * 是否为双列导航
	 */
	const isTwoColumnNav = useMemo(
		() => currentLayout === TWO_COLUMN_NAVIGATION,
		[currentLayout],
	);

	/**
	 * 是否为混合导航
	 */
	const isMixedNav = useMemo(
		() => currentLayout === MIXED_NAVIGATION,
		[currentLayout],
	);

	return {
		currentLayout,
		isSideNav,
		isTopNav,
		isMixedNav,
		isTwoColumnNav,
		sidebarWidth,
		sideCollapseWidth,
	};
}

import { GlobalSpin, Scrollbar } from "#src/components";
import { usePermissionStore, usePreferencesStore, useTabsStore } from "#src/store";
import { theme } from "antd";
import KeepAlive, { useKeepaliveRef } from "keepalive-for-react";
import { useEffect, useMemo } from "react";
import { useLocation, useOutlet } from "react-router";

export interface LayoutContentProps { }

export default function LayoutContent() {
	const {
		token: { colorBgLayout },
	} = theme.useToken();
	const { pathname, search } = useLocation();
	const outlet = useOutlet();
	const aliveRef = useKeepaliveRef();
	const isRefresh = useTabsStore(state => state.isRefresh);
	const openTabs = useTabsStore(state => state.openTabs);
	const tabbarEnable = usePreferencesStore(state => state.tabbarEnable);
	const flatRouteList = usePermissionStore(state => state.flatRouteList);
	const transitionName = usePreferencesStore(state => state.transitionName);
	const transitionEnable = usePreferencesStore(state => state.transitionEnable);

	/**
	 * to distinguish different pages to cache
	 */
	const cacheKey = useMemo(() => {
		return pathname + search;
	}, [pathname, search]);

	/**
	 * 当使用关闭当前标签页、关闭右侧标签页、关闭左侧标签页、关闭其他标签页、关闭所有标签页功能时，需要清除这个标签页的缓存
	 */
	useEffect(() => {
		const cacheNodes = aliveRef.current?.getCacheNodes?.();
		cacheNodes?.forEach((node) => {
			if (!openTabs.has(node.cacheKey)) {
				aliveRef.current?.destroy(node.cacheKey);
			}
		});
	}, [openTabs]);

	/**
	 * 关闭多 tab 功能，清空所有的缓存页面
	 */
	useEffect(() => {
		if (!tabbarEnable) {
			const cacheNodes = aliveRef.current?.getCacheNodes?.();
			cacheNodes?.forEach((node) => {
				/* 不包含当前页面 */
				if (node.cacheKey !== cacheKey) {
					aliveRef.current?.destroy(node.cacheKey);
				}
			});
		}
	}, [tabbarEnable]);

	/* KeepAlive 的刷新 */
	useEffect(() => {
		/* 仅在启用标签栏时生效 */
		if (tabbarEnable && isRefresh) {
			aliveRef.current?.refresh();
		}
	}, [isRefresh]);

	/* 路由设置 keepAlive = false 则不缓存页面 */
	const keepAliveExclude = useMemo(() => {
		/**
		 * 如果不开启多 tab 功能，则不需要 KeepAlive 功能
		 * 为了保留页面的切换动画，只需要把所有的路由放到 exclude 数组中
		 */
		if (!tabbarEnable) {
			return Object.keys(flatRouteList);
		}
		return Object.entries(flatRouteList).reduce<string[]>((acc, [key, value]) => {
			if (value.handle.keepAlive === false) {
				acc.push(key);
			}
			return acc;
		}, []);
	}, [flatRouteList, tabbarEnable]);

	return (
		<main
			className="overflow-y-auto overflow-x-hidden flex-grow"
			style={
				{
					backgroundColor: colorBgLayout,
				}
			}
		>
			<Scrollbar>
				<GlobalSpin>
					<KeepAlive
						max={20}
						transition
						duration={300}
						cacheNodeClassName={transitionEnable ? `keepalive-${transitionName}` : undefined}
						exclude={keepAliveExclude}
						activeCacheKey={cacheKey}
						aliveRef={aliveRef}
					>
						{outlet}
					</KeepAlive>
				</GlobalSpin>
			</Scrollbar>
		</main>
	);
}

