import { findChildrenLen } from "./utils";

interface LayoutMenuProps {
	mode?: MenuProps["mode"]
	/**
	 * 是否自动展开菜单，用于解决水平菜单下子菜单展开自动关闭的问题
	 */
	autoOpenMenu?: boolean
	menus?: MenuItemType[]
	handleMenuSelect?: (key: string, mode: MenuProps["mode"]) => void
}

const emptyArray: MenuItemType[] = [];
export default function LayoutMenu({
	mode = "inline",
	autoOpenMenu,
	handleMenuSelect,
	menus = emptyArray,
}: LayoutMenuProps) {
	const matches = useMatches();
	const { sidebarCollapsed } = useContext(LayoutContext);
	const [openKeys, setOpenKeys] = useState<string[]>([]);
	const { isMobile } = useDeviceType();

	const getSelectedKeys = useMemo(
		() => matches.map(item => item.id),
		[matches],
	);

	const menuInlineCollapsedProp = useMemo(
		() => {
			/* inlineCollapsed 只在 inline 模式可用 */
			if (mode === "inline") {
				return { inlineCollapsed: isMobile ? false : sidebarCollapsed };
			}
			return {};
		},
		[mode, isMobile, sidebarCollapsed],
	);

	const handleOpenChange: MenuProps["onOpenChange"] = (keys) => {
		// eslint-disable-next-line unicorn/prefer-includes
		const latestOpenKey = keys.find(key => openKeys.indexOf(key) === -1);
		const isExistChildren = latestOpenKey
			? findChildrenLen(menus, latestOpenKey)
			: false;
		setOpenKeys(() => {
			if (isExistChildren) {
				return latestOpenKey ? [latestOpenKey] : [];
			}
			return keys;
		});
	};

	const menuOpenProps = useMemo(
		() => {
			/* inlineCollapsed 只在 inline 模式可用 */
			if (autoOpenMenu) {
				return {
					openKeys,
					onOpenChange: handleOpenChange,
				};
			}
			return {};
		},
		[autoOpenMenu, openKeys],
	);

	useEffect(() => {
		/* 如果菜单是收起的，则不需要自动展开，防止子路由激活，菜单自动弹出 */
		if (!sidebarCollapsed) {
			setOpenKeys(matches.map(item => item.id));
		}
	}, [matches]);

	return (
		<Menu
			/**
			 * min-w-0 flex-auto 解决在 Flex 布局中，Menu 没有按照预期响应式省略菜单
			 * @see https://ant-design.antgroup.com/components/menu#why-menu-do-not-responsive-collapse-in-flex-layout
			 */
			className="!border-none min-w-0 flex-auto"
			inlineIndent={16}
			{...menuInlineCollapsedProp}
			style={{ height: isMobile ? "100%" : "initial" }}
			mode={mode}
			// theme="dark"
			items={menus}
			{...menuOpenProps}
			selectedKeys={getSelectedKeys}
			onSelect={({ key }) => handleMenuSelect?.(key, mode)}
		/>
	);
}

import type { MenuItemType } from "./types";

import { isString } from "#src/utils";

/**
 * 将菜单树中的所有 label 转换为国际化文本
 * @param menus 原始菜单数组
 * @param t Translation 函数
 * @returns 转换后的菜单数组
 */
export function translateMenus(menus: MenuItemType[], t: (key: string) => string): MenuItemType[] {
	return menus.map((menu) => {
		const translatedMenu = {
			...menu,
			label: isString(menu.label) ? t(menu.label) : menu.label,
		};

		if (menu.children && menu.children.length > 0) {
			translatedMenu.children = translateMenus(menu.children, t);
		}

		return translatedMenu;
	});
}

/**
 * 通过路径查找菜单
 *
 * @param list 菜单列表
 * @param path 菜单路径
 * @returns 找到的菜单对象，未找到则返回 null
 */
export function findMenuByPath(
	list: MenuItemType[],
	path?: string,
): MenuItemType | null {
	for (const menu of list) {
		if (menu.key === path) {
			return menu;
		}
		const findMenu = menu.children && findMenuByPath(menu.children, path);
		if (findMenu) {
			return findMenu;
		}
	}
	return null;
}

/**
 * 通过路径查找根菜单
 *
 * @param menus 菜单列表
 * @param path 菜单路径，可选
 * @returns 包含查找到的菜单、根菜单和根菜单路径的对象
 */
export function findRootMenuByPath(menus: MenuItemType[], path?: string): {
	findMenu: MenuItemType | null
	rootMenu: MenuItemType | null
	rootMenuPath: string | null
} {
	// 初始化返回值
	let findMenu: MenuItemType | null = null;
	let rootMenu: MenuItemType | null = null;
	let rootMenuPath: string | null = null;

	// 如果没有提供路径，返回默认值
	if (!path) {
		return {
			findMenu: null,
			rootMenu: null,
			rootMenuPath: null,
		};
	}

	// 递归查找函数
	const find = (
		list: MenuItemType[],
		targetPath: string,
		parents: MenuItemType[] = [],
	): boolean => {
		for (const menu of list) {
			// 如果找到目标菜单
			if (menu.key === targetPath) {
				findMenu = menu;
				// 如果没有父级菜单，说明当前菜单就是根菜单
				if (parents.length === 0) {
					rootMenu = menu;
					rootMenuPath = menu.key;
				}
				else {
					// 获取最顶层的父级菜单
					rootMenu = parents[0];
					rootMenuPath = parents[0].key;
				}
				return true;
			}

			// 如果有子菜单，继续递归查找
			if (menu.children && menu.children.length > 0) {
				// 将当前菜单加入父级菜单数组
				const found = find(menu.children, targetPath, [...parents, menu]);
				if (found) {
					return true;
				}
			}
		}
		return false;
	};

	// 开始查找
	find(menus, path);

	return {
		findMenu,
		rootMenu,
		rootMenuPath,
	};
}

/**
 * 递归查找第一个子菜单路径下的最深层级的第一个菜单项
 *
 * @param splitSideNavItems 菜单列表
 * @returns 找到的最深层级的第一个菜单项
 */
export function findDeepestFirstItem(splitSideNavItems: MenuItemType[]): MenuItemType | null {
	// 如果列表为空，返回 null
	if (!splitSideNavItems || splitSideNavItems.length === 0) {
		return null;
	}

	// 获取第一个菜单项
	const firstItem = splitSideNavItems[0];

	// 如果当前项有子菜单，继续递归查找
	if (firstItem.children && firstItem.children.length > 0) {
		return findDeepestFirstItem(firstItem.children);
	}

	// 如果没有子菜单了，说明到达最底层，返回当前项
	return firstItem;
}

/**
 * 判断目标键是否在子路由列表中
 *
 * @param menuItems 菜单项数组
 * @param targetKey 目标键
 * @returns 如果目标键在子路由列表中，则返回 true；否则返回 false
 */
export function findChildrenLen(menuItems: MenuItemType[], targetKey: string) {
	const subRouteChildren: string[] = [];

	for (const { children, key } of menuItems) {
		if (Array.isArray(children) && children.length) {
			subRouteChildren.push(key);
		}
	}

	return subRouteChildren.includes(targetKey);
}

