import { isObject, message } from "#src/utils";

/**
 * 处理错误响应
 *
 * @param response 响应对象
 * @returns 响应对象
 */
export async function handleErrorResponse(response: Response) {
	try {
		// 将响应内容解析为 JSON 格式
		const data = await response.json();

		// 判断解析后的数据是否为对象类型
		if (isObject(data)) {
			// 将解析后的数据转换为包含错误信息的对象类型
			const json = data as { errorMsg?: string, message?: string };

			// 如果解析后的数据中包含 errorMsg 或 message 属性，则显示错误信息
			// 否则显示响应的状态文本作为错误信息
			message.error(json.errorMsg || json.message || response.statusText);
		}
		else {
			// 如果解析后的数据不是对象类型，则直接显示响应的状态文本作为错误信息
			message.error(response.statusText);
		}
	}
	catch (e) {
		// 如果解析 JSON 格式出错，则打印错误信息到控制台
		console.error("Error parsing JSON:", e);

		// 显示响应的状态文本作为错误信息
		message.error(response.statusText);
	}

	// 返回响应对象
	return response;
}

import { useGlobalStore } from "#src/store";

// 定义一个全局变量用于追踪当前有多少请求正在进行中
let requestCount = 0;

export const globalProgress = {
	/**
	 * 启动请求
	 *
	 * 如果请求计数为 0，则显示全局加载动画，并将请求计数加 1。
	 */
	start() {
		if (requestCount === 0) {
			// 显示全局加载动画
			useGlobalStore.getState().openGlobalSpin();
		}
		// 请求计数加 1
		requestCount++;
	},

	/**
	 * 请求完成后的回调函数
	 *
	 * @description 将请求计数减 1，并保证请求计数不会小于 0；
	 *              如果请求计数为 0，则隐藏全局加载动画
	 */
	done() {
		// 请求计数减 1，但保证请求计数不会小于 0
		requestCount = Math.max(requestCount - 1, 0);
		if (requestCount === 0) {
			// 隐藏全局加载动画
			useGlobalStore.getState().closeGlobalSpin();
		}
	},

	/**
	 * 强制完成请求
	 *
	 * 将请求计数直接设置为0，并隐藏全局加载动画
	 */
	forceFinish() {
		// 直接将请求计数设置为 0
		requestCount = 0;
