import type { MenuProps } from "antd";
import { useTabsStore } from "#src/store";
import {
	CloseOutlined,
	RedoOutlined,
	SwapOutlined,
	VerticalAlignBottomOutlined,
	VerticalAlignMiddleOutlined,
	VerticalAlignTopOutlined,
} from "@ant-design/icons";
import { useKeepAliveContext } from "keepalive-for-react";
import { useCallback, useMemo } from "react";

import { useTranslation } from "react-i18next";

const homePath = import.meta.env.VITE_BASE_HOME_PATH;
/**
 * 标签页操作的键值对象
 * @readonly
 * @enum {string}
 * @property {string} REFRESH - 重新加载当前标签页
 * @property {string} CLOSE - 关闭当前标签页
 * @property {string} CLOSE_RIGHT - 关闭右侧标签页
 * @property {string} CLOSE_LEFT - 关闭左侧标签页
 * @property {string} CLOSE_OTHERS - 关闭其他标签页
 * @property {string} CLOSE_ALL - 关闭所有标签页
 */
export const TabActionKeys = {
	REFRESH: "refresh",
	CLOSE: "close",
	CLOSE_RIGHT: "closeRight",
	CLOSE_LEFT: "closeLeft",
	CLOSE_OTHERS: "closeOthers",
	CLOSE_ALL: "closeAll",
} as const;

export type TabActionKey = typeof TabActionKeys[keyof typeof TabActionKeys];

/**
 * 自定义钩子，用于处理标签页的下拉菜单
 * @returns {[Function, Function]} 返回一个元组，包含菜单项生成函数和菜单点击处理函数
 */
export function useDropdownMenu() {
	const { t } = useTranslation();
	const {
		openTabs,
		activeKey,
		removeTab,
		closeLeftTabs,
		closeRightTabs,
		closeOtherTabs,
		closeAllTabs,
		setIsRefresh,
	} = useTabsStore();
	const { refresh } = useKeepAliveContext();
	/**
	 * 生成菜单项
	 * @param {string} tabKey - 当前标签页的键
	 * @returns {MenuProps["items"]} 菜单项配置
	 */
	const items = useCallback((tabKey: string): MenuProps["items"] => {
		const isOnlyTab = openTabs.size === 2 && openTabs.has(homePath);
		const isLastTab = Array.from(openTabs.keys()).pop() === tabKey;
		return [
			{
				key: TabActionKeys.REFRESH,
				icon: <RedoOutlined rotate={270} />,
				label: t("preferences.tabbar.contextMenu.refresh"),
				disabled: activeKey !== tabKey,
			},
			{
				key: TabActionKeys.CLOSE,
				icon: <CloseOutlined />,
				label: t("preferences.tabbar.contextMenu.close"),
				disabled: tabKey === homePath,
			},
			{ type: "divider" },
			{
				key: TabActionKeys.CLOSE_LEFT,
				icon: <VerticalAlignBottomOutlined rotate={90} />,
				label: t("preferences.tabbar.contextMenu.closeLeft"),
				disabled: tabKey === homePath || isOnlyTab,
			},
			{
				key: TabActionKeys.CLOSE_RIGHT,
				icon: <VerticalAlignTopOutlined rotate={90} />,
				label: t("preferences.tabbar.contextMenu.closeRight"),
				disabled: tabKey === homePath || isOnlyTab || isLastTab,
			},
			{ type: "divider" },
			{
				key: TabActionKeys.CLOSE_OTHERS,
				icon: <VerticalAlignMiddleOutlined rotate={90} />,
				label: t("preferences.tabbar.contextMenu.closeOthers"),
				disabled: tabKey === homePath || isOnlyTab,
			},
			{
				key: TabActionKeys.CLOSE_ALL,
				icon: <SwapOutlined />,
				label: t("preferences.tabbar.contextMenu.closeAll"),
				disabled: tabKey === homePath,
			},
		];
	}, [t, activeKey, homePath, openTabs]);

	/**
	 * 定义菜单操作与对应的处理函数
	 */
	const actions = useMemo(() => ({
		[TabActionKeys.REFRESH]: (currentPath: string) => {
			// 刷新 KeepAlive 缓存的页面
			refresh(currentPath);
			// 重新渲染页面
			setIsRefresh(true);
		},
		[TabActionKeys.CLOSE]: removeTab,
		[TabActionKeys.CLOSE_RIGHT]: closeRightTabs,
		[TabActionKeys.CLOSE_LEFT]: closeLeftTabs,
		[TabActionKeys.CLOSE_OTHERS]: closeOtherTabs,
		[TabActionKeys.CLOSE_ALL]: closeAllTabs,
	}), [removeTab, closeRightTabs, closeLeftTabs, closeOtherTabs, closeAllTabs]);

	/**
	 * 处理菜单点击事件
	 * @param {string} menuKey - 被点击的菜单项键
	 * @param {string} nodeKey - 当前标签页的键
	 */
	const onClickMenu = useCallback((menuKey: string, nodeKey: string) => {
		const action = actions[menuKey as keyof typeof actions];
		if (action) {
			action(nodeKey);
		}
	}, [actions]);

	return [items, onClickMenu] as const;
}

import type { ButtonProps } from "antd";

import { BasicButton } from "#src/components";
import { useDeviceType, usePreferences } from "#src/hooks";
import { useAuthStore, usePreferencesStore } from "#src/store";

import { CopyOutlined, RedoOutlined, SettingOutlined } from "@ant-design/icons";
import { Badge, Divider, Drawer } from "antd";
import { useState } from "react";
import { useTranslation } from "react-i18next";
import { useNavigate } from "react-router";

import { Animation, BuiltinTheme, PreferencesLayout, SiteTheme, Tabbar } from "./blocks";

export function Preferences({ ...restProps }: ButtonProps) {
	const { t } = useTranslation();
	const navigate = useNavigate();
	const [isOpen, setIsOpen] = useState(false);
	const { isMobile } = useDeviceType();
	const { reset, isDefault } = usePreferences();
	const preferences = usePreferencesStore();
	const logout = useAuthStore(state => state.logout);

	const clearAndLogout = async () => {
		await logout();
		usePreferencesStore.persist.clearStorage();
		navigate("/login");
	};

	const handleCopyPreferences = async () => {
		const data = JSON.stringify(preferences, null, 2);
		await navigator.clipboard.writeText(data);
		window.$modal?.success?.({
			title: t("preferences.copyPreferencesSuccessTitle"),
			content: t("preferences.copyPreferencesSuccess"),
		});
	};

	return (
		<>
			<BasicButton
				type="text"
				{...restProps}
				onClick={(e) => {
					restProps?.onClick?.(e);
					setIsOpen(true);
				}}
			>
				<SettingOutlined />
			</BasicButton>
			<Drawer
				title={t("preferences.title")}
				placement="right"
				onClose={() => {
					setIsOpen(false);
				}}
				extra={(
					<Badge
						style={{ width: 8, height: 8 }}
						dot={!isDefault}
						color="blue"
						offset={[-5, 5]}
					>
						<BasicButton
							onPointerDown={() => !isDefault && reset()}
							type="text"
							icon={<RedoOutlined rotate={270} />}
						/>
					</Badge>
				)}
				footer={(
					<div className="flex justify-between">
						<BasicButton
							icon={<CopyOutlined rotate={180} />}
							onPointerDown={handleCopyPreferences}
						>
							{t("preferences.copyPreferences")}
						</BasicButton>
						<BasicButton
							type="text"
							onPointerDown={clearAndLogout}
						>
							{t("preferences.clearAndLogout")}
						</BasicButton>
					</div>
				)}
				{...(isMobile
					? {
						width: "100vw",
					}
					: {})}
				open={isOpen}
			>
				<div
					style={{
						display: "flex",
						flexDirection: "column",
						alignItems: "center",
					}}
				>
					<Divider>{t("preferences.theme.title")}</Divider>
					<SiteTheme />
					<Divider>{t("preferences.theme.builtin.title")}</Divider>
					<BuiltinTheme />
					<Divider>{t("preferences.layout.title")}</Divider>
					<PreferencesLayout />
					<Divider>{t("preferences.tabbar.title")}</Divider>
					<Tabbar />
					<Divider>{t("preferences.animation.title")}</Divider>
					<Animation />
				</div>
			</Drawer>
		</>
	);
}

import type { BreadcrumbProps } from "antd";

import { isString } from "#src/utils";

import { Breadcrumb } from "antd";
import { useTranslation } from "react-i18next";
import { useMatches } from "react-router";

const itemRender: BreadcrumbProps["itemRender"] = (route, params, routes) => {
	const last = routes.indexOf(route) === routes.length - 1;
	return last || !route.path
		? (
			<span>{route.title}</span>
		)
		: (
			<span>{route.title}</span>
			// <NavLink to={route.path}>{route.title}</NavLink>
		);
};

export function BreadcrumbViews() {
	const { t } = useTranslation();
	const matches = useMatches();

	return (
		<Breadcrumb
			className="hidden md:block"
			separator="->"
			// https://ant.design/components/breadcrumb#use-with-browserhistory
			itemRender={itemRender}
			items={matches
				// filter - root route & index route
				.filter(match => match.handle && !match.pathname.endsWith("/"))
				.map((match) => {
					return {
						title: isString(match.handle?.title) ? t(match.handle?.title) : match.handle?.title,
						path: match.pathname,
					};
				})}
		/>
	);
}

import { isNumber } from "#src/utils";
import { MinusOutlined, PlusOutlined } from "@ant-design/icons";

import { Button, InputNumber } from "antd";

export interface NumberInputSpinnerProps {
	children: React.ReactNode
	name: string
	min: number
	max: number
	value?: number
	disabled?: boolean
	onChange?: (a: string, b: number) => void
}

export function NumberInputSpinner({
	children,
	disabled,
	value,
	name,
	onChange,
	min,
	max,
}: NumberInputSpinnerProps) {
	const isMax = value === max;
	const isMin = value === min;

	const handleDecrement = () => {
		if (value && isNumber(value) && !isMin) {
			onChange?.(name, value - 1);
		}
	};
	const handleIncrement = () => {
		if (value && isNumber(value) && !isMax) {
			onChange?.(name, value + 1);
		}
	};

	const handleChange = (v: number | null) => {
		if (v && isNumber(v)) {
			onChange?.(name, v);
		}
	};

	return (
		<div className="hover:bg-accent my-1 flex w-full items-center justify-between rounded-md px-2 py-2.5">
			<span className="flex items-center text-sm">{children}</span>
			<InputNumber
				className="w-40 [&_input]:!text-center [&_.ant-input-number-group-addon]:px-0"
				min={min}
				max={max}
				precision={0}
				changeOnWheel
				addonBefore={(
					<Button
						className="rounded-none"
						type="text"
						disabled={isMin}
						onPointerDown={handleDecrement}
						icon={<MinusOutlined />}
					/>
				)}
				addonAfter={(
					<Button
						className="rounded-none"
						type="text"
						disabled={isMax}
						onPointerDown={handleIncrement}
						icon={<PlusOutlined />}
					/>
				)}
				controls={false}
				disabled={disabled}
