					}}
					// onGetCaptcha={(phone) => {
					onGetCaptcha={() => {
						// console.log("phoneNumber:", phone);
						window.$message?.success(t("common.success"));
						return Promise.resolve();
					}}
					// onTiming={(count) => {
					// 	console.log("timing:", count);
					// }}
					rules={[
						{
							required: true,
						},
					]}
					phoneName="phoneNumber"
					name="captcha"
				/>

				<Form.Item>
					<Button
						block
						type="primary"
						htmlType="submit"
						loading={loading}
					>
						{t("authority.login")}
					</Button>
				</Form.Item>

				<div className="text-sm text-center">
					<BasicButton
						type="link"
						icon={<LeftOutlined />}
						className="px-1"
						onPointerDown={() => {
							setFormMode("login");
						}}
					>
						{t("common.back")}
					</BasicButton>
				</div>
			</Form>
		</>
	);
