		setPreferences({
			builtinTheme: value,
			themeColorPrimary: builtinThemePresets.find(item => item.value === value)?.color,
		});
	}

	return (
		<>
			<ul className="flex justify-between flex-wrap w-full gap-3 p-0 m-0 list-none">
				{
					builtinThemePresets.map((item) => {
						const innerBlock = (
							<li
								// className="last:mr-auto"
								key={item.value}
								onClick={() => handleClick(item.value)}
							>
								<dl className="mb-0">
									<dd
										className={cn(
											"relative py-4 px-9 outline outline-1 outline-gray-300 dark:outline-gray-700 rounded-md cursor-pointer",
											"before:content-[''] before:absolute before:left-1/2 before:top-1/2 before:h-0 before:w-0 before:rounded-sm before:opacity-0 before:outline before:outline-2 before:outline-transparent",
											item.value === builtinTheme ? "" : "before:transition-all before:duration-300",
											item.value === builtinTheme ? "" : "before:hover:outline-blue-600 dark:before:hover:outline-blue-700 before:hover:left-0 before:hover:top-0 before:hover:h-full before:hover:w-full before:hover:p-1 before:hover:opacity-100",
											{ "outline-2 outline-blue-600 dark:outline-blue-700": item.value === builtinTheme },
										)}
									>
										<div
											className="rounded-md size-5"
											style={{ backgroundColor: item.value === "custom" ? color : item.color }}
										>
											<span className="hidden">{item.label}</span>
											<span className="hidden">{item.color}</span>
										</div>
									</dd>

									<dt className="mt-2.5 flex gap-1 justify-center text-xs opacity-90">
										<span className="">{item.label}</span>
									</dt>
								</dl>
							</li>
						);
						if (item.value === "custom") {
							return (
								<ColorPicker key={item.value} value={color} onChangeComplete={handleColorChange}>
									{innerBlock}
								</ColorPicker>
							);
						}
						return innerBlock;
					})
				}
			</ul>
		</>
	);
}

import { usePreferencesStore } from "#src/store";
import { cn } from "#src/utils";

import { useTranslation } from "react-i18next";
import { SwitchItem } from "../../switch-item";

const transitionPreset = [
	"fade",
	"fade-slide",
	"fade-up",
	"fade-down",
	"fade-zoom",
];

export function Animation() {
	const transitionEnable = usePreferencesStore(state => state.transitionEnable);
	const transitionLoading = usePreferencesStore(state => state.transitionLoading);
	const transitionProgress = usePreferencesStore(state => state.transitionProgress);
	const transitionName = usePreferencesStore(state => state.transitionName);
	const setPreferences = usePreferencesStore(state => state.setPreferences);
	const { t } = useTranslation();

	function handleClick(value: string) {
		setPreferences("transitionName", value);
	}

	return (
		<>
			<SwitchItem
				name="transitionProgress"
				checked={transitionProgress}
				onChange={(name, value) => setPreferences(name, value)}
			>
				{t("preferences.animation.progress")}
			</SwitchItem>
			<SwitchItem
				name="transitionLoading"
				checked={transitionLoading}
				onChange={(name, value) => setPreferences(name, value)}
			>
				{t("preferences.animation.loading")}
			</SwitchItem>
			<SwitchItem
				name="transitionEnable"
				checked={transitionEnable}
				onChange={(name, value) => setPreferences(name, value)}
			>
				{t("preferences.animation.transition")}
			</SwitchItem>
			<ul
				className="w-full flex flex-wrap justify-between gap-x-3 gap-y-5 list-none px-0"
			>
				{
					transitionPreset.map(item => (
						<li
							key={item}
							onClick={() => handleClick(item)}
							className={cn(
								"relative p-2 outline outline-1 outline-gray-300 dark:outline-gray-700 cursor-pointer rounded-md",
								"before:content-[''] before:absolute before:left-1/2 before:top-1/2 before:h-0 before:w-0 before:rounded-sm before:opacity-0 before:outline before:outline-2 before:outline-transparent",
								item === transitionName ? "" : "before:transition-all before:duration-300",
								item === transitionName ? "" : "before:hover:outline-blue-600 dark:before:hover:outline-blue-700 before:hover:left-0 before:hover:top-0 before:hover:h-full before:hover:w-full before:hover:p-1 before:hover:opacity-100",
								{ "outline-2 outline-blue-600 dark:outline-blue-700": item === transitionName },
							)}
						>
							<div
								className={cn(
									"dark:bg-gray-700",
									"bg-gray-100 h-10 w-12 rounded-md text-xs flex items-center justify-center text-center",
									{
										"fade-slide": item === "fade-slide",
										"fade": item === "fade",
										"fade-up": item === "fade-up",
										"fade-down": item === "fade-down",
										"fade-zoom": item === "fade-zoom",
									},
								)}
							>
								<span className="scale-75 text-opacity-75">{item}</span>
							</div>
						</li>
					))
				}
			</ul>
		</>
	);
}

import type { ThemeType } from "#src/store";
import type { InputNumberProps } from "antd";

import { FollowSystemIcon, MoonIcon, SunIcon } from "#src/icons";
import { usePreferencesStore } from "#src/store";

import { cn } from "#src/utils";
import { InputNumber, Slider } from "antd";
import { useTranslation } from "react-i18next";

import { SwitchItem } from "../../switch-item";

export function SiteTheme() {
	const { t } = useTranslation();
	const {
		theme,
		colorBlindMode,
		colorGrayMode,
		themeRadius,
		changeSiteTheme,
		setPreferences,
	} = usePreferencesStore();

	const themePresets = [
		{
			name: t("preferences.theme.light"),
			icon: <SunIcon className="text-xl" />,
			type: "light",
		},
		{
			name: t("preferences.theme.dark"),
			icon: <MoonIcon className="text-xl" />,
			type: "dark",
		},
		{
			name: t("preferences.theme.followSystem"),
			icon: <FollowSystemIcon className="text-xl" />,
			type: "auto",
		},
	] as const;

	function handleClick(value: ThemeType) {
		changeSiteTheme(value);
	}

	const handleChange: InputNumberProps["onChange"] = (newValue) => {
		setPreferences("themeRadius", newValue!);
	};

	return (
		<>
			<ul className="flex justify-between w-full gap-3 p-0 m-0 list-none">
				{
					themePresets.map(item => (
						<li
							key={item.type}
							onClick={() => handleClick(item.type)}
						>
							<dl className="mb-0">
								<dd
									className={cn(
										"relative py-4 px-10 outline outline-1 outline-gray-300 dark:outline-gray-700 rounded-md cursor-pointer",
										"before:content-[''] before:absolute before:left-1/2 before:top-1/2 before:h-0 before:w-0 before:rounded-sm before:opacity-0 before:outline before:outline-2 before:outline-transparent",
										item.type === theme ? "" : "before:transition-all before:duration-300",
										item.type === theme ? "" : "before:hover:outline-blue-600 dark:before:hover:outline-blue-700 before:hover:left-0 before:hover:top-0 before:hover:h-full before:hover:w-full before:hover:p-1 before:hover:opacity-100",
										{ "outline-2 outline-blue-600 dark:outline-blue-700": item.type === theme },
									)}
								>
									{item.icon}
								</dd>

								<dt className="mt-2.5 flex gap-1 justify-center text-xs opacity-90">
									<span className="">{item.name}</span>
								</dt>
							</dl>
						</li>
					))
				}
			</ul>

			<SwitchItem
				name="colorBlindMode"
				checked={colorBlindMode}
				onChange={(name, value) => setPreferences(name, value)}
			>
				{t("preferences.theme.colorBlindMode")}
			</SwitchItem>
			<SwitchItem
				name="colorGrayMode"
				checked={colorGrayMode}
				onChange={(name, value) => setPreferences(name, value)}
			>
				{t("preferences.theme.grayMode")}
			</SwitchItem>
			<div className="flex justify-between w-full px-2">
				<span className="flex items-center text-sm">
					{t("preferences.theme.radius")}
				</span>
				<div className="w-1/3">
					<Slider
						rootClassName="w-full"
						min={0}
						max={16}
						onChange={handleChange}
						value={themeRadius}
					/>
				</div>
				<div>
					<InputNumber
						className="ml-4"
						min={0}
						max={16}
						value={themeRadius}
						onChange={handleChange}
					/>
				</div>
			</div>

		</>
	);
}
